// Get the news array from the Bright Data node
const news = $input.first().json.news || [];

// Filter out YouTube videos, keep only real news
const filtered = news.filter(item => {
  const link = (item.link || "").toLowerCase();
  const isVideo = link.includes("youtube.com") || link.includes("youtu.be");
  return !isVideo && item.title && item.link;
});

// Dedupe by title
const seen = new Set();
const deduped = filtered.filter(item => {
  if (seen.has(item.title)) return false;
  seen.add(item.title);
  return true;
});

// Keep top 5
const top5 = deduped.slice(0, 5);

// Return each story as a separate item (for the loop ahead)
return top5.map(item => ({ json: item }));

// Web Unlocker may return ["markdown..."], a string, or an object
let raw = $input.first().json;

let content = "";
if (Array.isArray(raw)) {
  content = raw[0] || "";
} else if (typeof raw === "string") {
  content = raw;
} else {
  // Object: take the longest string found
  for (const key in raw) {
    if (typeof raw[key] === "string" && raw[key].length > content.length) {
      content = raw[key];
    }
    // Sometimes it's raw.data[0] or similar
    if (Array.isArray(raw[key]) && typeof raw[key][0] === "string") {
      if (raw[key][0].length > content.length) content = raw[key][0];
    }
  }
}

// Try to drop everything before the real article start
// Many sites put the title as "# " then the body — keep the last H1 section
const h1Split = content.split(/\n# /);
if (h1Split.length > 1) {
  content = "# " + h1Split[h1Split.length - 1];
}

// Strip markdown links [text](url) → keep the text
content = content.replace(/\[([^\]]*)\]\([^)]*\)/g, "$1");
// Strip images ![...](...)
content = content.replace(/!\[[^\]]*\]\([^)]*\)/g, "");

// Keep only real text lines (> 50 chars)
let lines = content.split("\n").map(l => l.trim()).filter(l => l.length > 50);
let cleaned = lines.join("\n\n").slice(0, 2500);

return [{
  json: {
    title: $('Loop Over News Stories').item.json.title,
    link: $('Loop Over News Stories').item.json.link,
    source: $('Loop Over News Stories').item.json.source,
    content: cleaned
  }
}];
